class TrieNode:
    def __init__(self, char):
        self.val = char
        self.left = self.right = None

class Solution:
    def insert(self, root, word):
        node = root
        for char in word:
            if not node.left:
                node.left = TrieNode(char)
            elif not node.right:
                node.right = TrieNode(char)
            if char < node.val:
                node = node.left
            else:
                node = node.right
        return True

if __name__ == '__main__':
    solution = Solution()
    root = None
    word = input()
    result = solution.insert(root, word)
    print(result)

