// Definition for a Node. 
function Node(val, children) {
    this.val = val;
    this.children = children;
}

class TrieNode {
    constructor(val) {
        this.val = val;
        this.children = {};
    }
}

class Solution {
    insert(root, ch) {
        if (!root) return new TrieNode(ch);
        if (ch < root.val) root.left = this.insert(root.left, ch);
        else root.right = this.insert(root.right, ch);
        return root;
    }
}

var solution = new Solution();
var root = null;
var word = readline();
